const raw = $input.first().json;
const data = raw.body ?? raw;

const appUrl = 'https://itsnomatataworkspace.vercel.app';
const appName = 'Nomatata';

const actionUrl = data.actionUrl
  ? (data.actionUrl.startsWith('http')
      ? data.actionUrl
      : `${appUrl}${data.actionUrl}`)
  : appUrl;

const fullName = data.fullName ?? data.full_name ?? 'Team Member';
const firstName = fullName.split(' ')[0];

const metadata = data.metadata ?? {};
metadata.sentAt = new Date().toISOString();
metadata.notificationId = data.referenceId ?? data.entityId ?? 'unknown';

// Check if frontend already generated email templates
const hasPreGeneratedEmail = data.emailHtml && data.subject;

return [{
  json: {
    to: data.to ?? '',
    fullName,
    firstName,
    title: data.title ?? 'You have a new notification',
    message: data.message ?? '',
    type: data.type ?? 'general',
    priority: data.priority ?? 'medium',
    actionUrl,
    metadata,
    appName,
    appUrl,
    emailHtml: data.emailHtml || null,
    subject: data.subject || null,
    hasPreGeneratedEmail,
    originalPayload: data
  }
}];

const data = $input.first().json;

// Use pre-generated email from frontend
return [{
  json: {
    to: data.to,
    fullName: data.fullName,
    firstName: data.firstName,
    subject: data.subject,
    type: data.type,
    priority: data.priority,
    actionUrl: data.actionUrl,
    emailHtml: data.emailHtml,
    metadata: data.metadata,
    source: 'frontend-generated'
  }
}];

